/**
 * @suppress
 */
public object FfiConverterTypeAppView: FfiConverter<AppView, Pointer> {

    override fun lower(value: AppView): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): AppView {
        return AppView(value)
    }

    override fun read(buf: ByteBuffer): AppView {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: AppView) = 8UL

    override fun write(value: AppView, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



