/**
 * Errors surfaced to host languages (one flat message; the SDK's typed errors
 * are stringified at the boundary).
 */
sealed class RockskyException: kotlin.Exception() {
    
    class Generic(
        
        val `reason`: kotlin.String
        ) : RockskyException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<RockskyException> {
        override fun lift(error_buf: RustBuffer.ByValue): RockskyException = FfiConverterTypeRockskyError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeRockskyError : FfiConverterRustBuffer<RockskyException> {
    override fun read(buf: ByteBuffer): RockskyException {
        

        return when(buf.getInt()) {
            1 -> RockskyException.Generic(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: RockskyException): ULong {
        return when(value) {
            is RockskyException.Generic -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
        }
    }

    override fun write(value: RockskyException, buf: ByteBuffer) {
        when(value) {
            is RockskyException.Generic -> {
                buf.putInt(1)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




